/**
 * Calculates rewards based on the provided score and time.
 * This is a simple example of reward logic. In a real game, this might involve
 * more complex factors like level difficulty, player level, daily bonuses,
 * streaks, or event-based multipliers.
 * @param {number} score The score achieved by the player.
 * @param {number} time The time taken to complete the level (in seconds).
 * @returns {{coins: number, gems: number}} An object containing the calculated coins and gems.
 */
const calculateRewards = (score, time) => {
    let coins = 0;
    let gems = 0;

    // Base rewards: Higher score gives more coins and a few gems
    coins += Math.floor(score * 0.5); // 0.5 coins per point
    gems += Math.floor(score / 250); // 1 gem for every 250 points

    // Time-based bonuses: Faster completion yields bonus gems
    if (time > 0) { // Ensure time is positive to avoid division by zero or negative logic
        if (time < 30) { // Very fast completion
            gems += 5;
            coins += 25;
        } else if (time < 60) { // Fast completion
            gems += 2;
            coins += 10;
        }
        // Further logic could penalize for very slow times
    }

    // Score-tier bonuses: Significant bonuses for reaching certain score thresholds
    if (score >= 1000) {
        gems += 10;
        coins += 100;
    } else if (score >= 500) {
        gems += 3;
        coins += 30;
    }

    // Ensure rewards are not negative
    coins = Math.max(0, coins);
    gems = Math.max(0, gems);

    return { coins, gems };
};

